const body = $input.first().json.body;
const expectedPassphrase = $env.TRADINGVIEW_WEBHOOK_SECRET;

if (!body || !body.passphrase) {
  throw new Error('Missing passphrase in request body');
}

if (body.passphrase !== expectedPassphrase) {
  throw new Error('Invalid passphrase — request rejected');
}

const { passphrase, ...safeBody } = body;

return [{
  json: {
    validated: true,
    payload: safeBody,
    received_at: new Date().toISOString()
  }
}];

const payload = $input.first().json.payload;

const symbol = payload.ticker || payload.symbol || '';
const side = (payload.action || payload.side || payload.order || '').toLowerCase();
const price = parseFloat(payload.price || payload.close || 0);
const timeframe = payload.interval || payload.timeframe || '';
const strategy = payload.strategy || payload.strategy_name || 'unknown';
const exchange = payload.exchange || '';
const volume = parseFloat(payload.volume || 0);
const comment = payload.comment || payload.message || '';

if (!symbol) {
  throw new Error('Missing required field: symbol/ticker');
}

if (!['buy', 'sell', 'long', 'short', 'close', 'exit'].includes(side)) {
  throw new Error(`Invalid side: ${side}. Must be one of: buy, sell, long, short, close, exit`);
}

const normalizedSide = (side === 'long' || side === 'buy') ? 'buy' : (side === 'short' || side === 'sell') ? 'sell' : side;

return [{
  json: {
    signal: {
      symbol: symbol.toUpperCase(),
      side: normalizedSide,
      price: price,
      timeframe: timeframe,
      strategy: strategy,
      exchange: exchange,
      volume: volume,
      comment: comment,
      source: 'tradingview',
      received_at: $input.first().json.received_at
    }
  }
}];
